import { userResolvers } from "./resolvers/user.js";
import { postResolvers } from "./resolvers/post.js";
import { DateTime, JSONScalar } from "./scalars.js";

// Top-level resolver map. Per-entity resolvers live in src/resolvers/<entity>.ts
// to keep this file as a thin index — easier to grep when an operation breaks.
export const resolvers = {
  DateTime,
  JSON: JSONScalar,
  Query: {
    health: () => "ok",
    listUsers: userResolvers.list,
    getUser: userResolvers.get,
    listPosts: postResolvers.list,
    getPost: postResolvers.get,
  },
  Mutation: {
    createUser: userResolvers.create,
    updateUser: userResolvers.update,
    deleteUser: userResolvers.remove,
    createPost: postResolvers.create,
    updatePost: postResolvers.update,
    deletePost: postResolvers.remove,
  },
};

