// In-memory CRUD for Post. Replace with a real DB call (Prisma, Drizzle,
// raw pg, etc.) when you wire up persistence — the resolver signatures stay
// the same so the GraphQL schema does not change.

type Post = {
  id: string;
  title: string;
  body: string;
  published: boolean;
};

const store = new Map<string, Post>();

export const postResolvers = {
  list: (_: unknown, args: { page?: number; pageSize?: number }) => {
    const page = Math.max(1, args.page ?? 1);
    const pageSize = Math.max(1, Math.min(100, args.pageSize ?? 20));
    const all = Array.from(store.values());
    const start = (page - 1) * pageSize;
    return {
      items: all.slice(start, start + pageSize),
      total: all.length,
      page,
      pageSize,
    };
  },
  get: (_: unknown, args: { id: string }) => store.get(String(args.id)) ?? null,
  create: (_: unknown, args: { input: Post }) => {
    const id = String(args.input.id ?? crypto.randomUUID());
    const row = { ...args.input, id: id } as Post;
    store.set(id, row);
    return row;
  },
  update: (_: unknown, args: { input: Post }) => {
    const id = String(args.input.id);
    const existing = store.get(id);
    if (!existing) throw new Error(`Post ${id} not found`);
    const next = { ...existing, ...args.input };
    store.set(id, next);
    return next;
  },
  remove: (_: unknown, args: { id: string }) => {
    return store.delete(String(args.id));
  },
};

